namespace sv_5edd345ffa804259b945e1a8d7048b26.Services;

/// <summary>
/// Scoped service that holds the currently selected warehouse for a single circuit.
/// Components subscribe to <see cref="OnChange"/> to react when the selection changes.
/// </summary>
public sealed class WarehouseStateService
{
    public static readonly IReadOnlyList<(string Id, string Name)> AvailableWarehouses =
    [
        ("WH-A", "Warehouse A"),
        ("WH-B", "Warehouse B"),
        ("WH-C", "Warehouse C"),
    ];

    private string _currentWarehouseId = AvailableWarehouses[0].Id;

    public string CurrentWarehouseId => _currentWarehouseId;

    public string CurrentWarehouseName =>
        AvailableWarehouses.First(w => w.Id == _currentWarehouseId).Name;

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (_currentWarehouseId == warehouseId)
            return;

        _currentWarehouseId = warehouseId;
        OnChange?.Invoke();
    }
}

namespace sv_5edd345ffa804259b945e1a8d7048b26.Services;

/// <summary>
/// Scoped service that provides low-stock alert counts and manages polling.
/// Polling is reference-counted — it runs while at least one component has called
/// <see cref="StartPolling"/> without a matching <see cref="StopPolling"/>.
/// All subscribers receive updates via <see cref="OnAlertUpdated"/>.
/// </summary>
public sealed class InventoryAlertService : IDisposable
{
    private readonly WarehouseStateService _warehouseState;
    private readonly Random _random = new();

    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private int _pollingRefCount;
    private int _lastCount;

    public int LastLowStockCount => _lastCount;

    /// <summary>
    /// Raised on the polling background thread whenever a new alert count arrives.
    /// Subscribers must marshal to the UI thread (e.g. via InvokeAsync).
    /// </summary>
    public event Func<Task>? OnAlertUpdated;

    public InventoryAlertService(WarehouseStateService warehouseState)
    {
        _warehouseState = warehouseState;
        _warehouseState.OnChange += HandleWarehouseChanged;
    }

    /// <summary>Simulates a database query returning a random low-stock count.</summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        return Task.FromResult(_random.Next(0, 16));
    }

    /// <summary>
    /// Increments the polling reference count.  Starts the background loop on the first call.
    /// </summary>
    public void StartPolling()
    {
        _pollingRefCount++;
        if (_pollingRefCount == 1)
            StartTimer();
    }

    /// <summary>
    /// Decrements the polling reference count.  Stops the background loop when it reaches zero.
    /// </summary>
    public void StopPolling()
    {
        _pollingRefCount = Math.Max(0, _pollingRefCount - 1);
        if (_pollingRefCount == 0)
            StopTimer();
    }

    private void StartTimer()
    {
        StopTimer();
        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        _ = PollLoopAsync(_cts.Token);
    }

    private void StopTimer()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
        _timer?.Dispose();
        _timer = null;
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        // Fire immediately on start, then every interval.
        await FetchAndNotifyAsync();

        while (_timer is not null && !ct.IsCancellationRequested)
        {
            try
            {
                if (!await _timer.WaitForNextTickAsync(ct))
                    break;
            }
            catch (OperationCanceledException)
            {
                break;
            }

            await FetchAndNotifyAsync();
        }
    }

    private async Task FetchAndNotifyAsync()
    {
        _lastCount = await GetLowStockCountAsync(_warehouseState.CurrentWarehouseId);
        if (OnAlertUpdated is not null)
            await OnAlertUpdated.Invoke();
    }

    private void HandleWarehouseChanged()
    {
        if (_pollingRefCount > 0)
        {
            // Restart the timer so the new warehouse gets an immediate refresh.
            StartTimer();
        }
    }

    public void Dispose()
    {
        _warehouseState.OnChange -= HandleWarehouseChanged;
        StopTimer();
    }
}

@using sv_5edd345ffa804259b945e1a8d7048b26.Services
@inject WarehouseStateService WarehouseState
@rendermode InteractiveServer

<div class="warehouse-selector d-flex align-items-center gap-2">
    <label class="form-label mb-0 text-nowrap fw-semibold" for="warehousePicker">Site:</label>
    <select id="warehousePicker"
            class="form-select form-select-sm"
            style="width:auto"
            value="@WarehouseState.CurrentWarehouseId"
            @onchange="OnWarehouseChanged">
        @foreach (var (id, name) in WarehouseStateService.AvailableWarehouses)
        {
            <option value="@id">@name</option>
        }
    </select>
</div>

@code {
    private void OnWarehouseChanged(ChangeEventArgs e)
    {
        var newId = e.Value?.ToString();
        if (!string.IsNullOrEmpty(newId))
        {
            WarehouseState.SetWarehouse(newId);
        }
    }
}

@using sv_5edd345ffa804259b945e1a8d7048b26.Services
@implements IDisposable
@inject InventoryAlertService AlertService
@rendermode InteractiveServer

<span class="badge rounded-pill @BadgeClass">@AlertService.LastLowStockCount</span>

@code {
    private string BadgeClass =>
        AlertService.LastLowStockCount switch
        {
            > 5 => "text-bg-danger",
            > 0 => "text-bg-warning",
            _   => "text-bg-success",
        };

    protected override void OnInitialized()
    {
        AlertService.OnAlertUpdated += HandleAlertUpdated;
    }

    private async Task HandleAlertUpdated()
    {
        await InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        AlertService.OnAlertUpdated -= HandleAlertUpdated;
    }
}

@page "/dashboard"
@using sv_5edd345ffa804259b945e1a8d7048b26.Services
@implements IDisposable
@inject WarehouseStateService WarehouseState
@inject InventoryAlertService AlertService
@rendermode InteractiveServer

<PageTitle>Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mt-3" style="max-width: 30rem;">
    <div class="card-body">
        <h5 class="card-title">@WarehouseState.CurrentWarehouseName</h5>
        <p class="card-text">
            Low-stock alerts:
            <span class="badge rounded-pill @BadgeClass fs-6">@AlertService.LastLowStockCount</span>
        </p>
        <p class="text-muted small mb-0">
            Polling every 10 seconds. Leave this page to stop polling.
        </p>
    </div>
</div>

@code {
    private string BadgeClass =>
        AlertService.LastLowStockCount switch
        {
            > 5 => "text-bg-danger",
            > 0 => "text-bg-warning",
            _   => "text-bg-success",
        };

    protected override void OnInitialized()
    {
        WarehouseState.OnChange += HandleStateChanged;
        AlertService.OnAlertUpdated += HandleAlertUpdated;
        AlertService.StartPolling();
    }

    private void HandleStateChanged() => InvokeAsync(StateHasChanged);

    private async Task HandleAlertUpdated() => await InvokeAsync(StateHasChanged);

    public void Dispose()
    {
        WarehouseState.OnChange -= HandleStateChanged;
        AlertService.OnAlertUpdated -= HandleAlertUpdated;
        AlertService.StopPolling();
    }
}

